module top_module(input [15:0] obf_in,
					 input [3:0] sel,
					 output reg out);always@(obf_in or sel)
			begin
				case(sel)
					4'b0000 : out = obf_in[0];
					4'b0001 : out = obf_in[1];	
					4'b0010 : out = obf_in[2]; 
					4'b0011 : out = obf_in[3];
					4'b0100 : out = obf_in[4];
					4'b0101 : out = obf_in[5];
					4'b0110 : out = obf_in[6];
					4'b0111 : out = obf_in[7];
					4'b1000 : out = obf_in[8];
					4'b1001 : out = obf_in[9];
					4'b1010 : out = obf_in[10];
					4'b1011 : out = obf_in[11];
					4'b1100 : out = obf_in[12];
					4'b1101 : out = obf_in[13];
					4'b1110 : out = obf_in[14];
					4'b1111 : out = obf_in[15];
				endcase
			end		




endmodule
